#include<bits/stdc++.h>
using namespace std;
int dp[40010];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        int v,w,c;
        scanf("%d%d%d",&v,&w,&c);
        c=min(c,m/w);
        for(int j=1;j<=c;j++)
        {
            for(int k=m;k>=w;k--)
            {
                dp[k]=max(dp[k],dp[k-w]+v);
            }
        }
    }
    printf("%d",dp[m]);
    return 0;
}
